const igData = $('Obtener Comentarios IG').first().json;
const fbData = $('Obtener Comentarios FB').first().json;
const comments = [];

// Procesar comentarios de IG
if (igData.data) {
  for (const post of igData.data) {
    if (post.comments?.data) {
      for (const comment of post.comments.data) {
        // Solo comentarios de las últimas 2 horas sin respuesta
        const commentTime = new Date(comment.timestamp);
        const twoHoursAgo = new Date(Date.now() - 2 * 60 * 60 * 1000);
        if (commentTime > twoHoursAgo && (!comment.replies || comment.replies.data.length === 0)) {
          comments.push({
            platform: 'instagram',
            post_id: post.id,
            comment_id: comment.id,
            text: comment.text,
            username: comment.username,
            timestamp: comment.timestamp
          });
        }
      }
    }
  }
}

// Procesar comentarios de FB
if (fbData.data) {
  for (const post of fbData.data) {
    if (post.comments?.data) {
      for (const comment of post.comments.data) {
        const commentTime = new Date(comment.created_time);
        const twoHoursAgo = new Date(Date.now() - 2 * 60 * 60 * 1000);
        if (commentTime > twoHoursAgo) {
          comments.push({
            platform: 'facebook',
            post_id: post.id,
            comment_id: comment.id,
            text: comment.message,
            username: comment.from?.name || 'unknown',
            timestamp: comment.created_time
          });
        }
      }
    }
  }
}

return comments.map(c => ({ json: c }));

const response = $input.first().json;
const text = response.content[0].text;
const jsonMatch = text.match(/\{[\s\S]*\}/);
const classification = JSON.parse(jsonMatch[0]);
const original = $('Filtrar Comentarios Nuevos').first().json;

return [{
  json: {
    ...original,
    ...classification
  }
}];

